html,
body {
  color: black;
  background-color: white;
  font: 16px/1 monospace;
  padding: 0;
  margin: 0;
}

table {
  box-sizing: content-box;
  border: 3px solid black;
  padding: 5px;
  background: blue content-box;
  border-spacing: 0;
}

td {
  padding: 1px;
}

div {
  width: 75px;
  height: 75px;
}

.grid {
  display: grid;
}
